  ('Simple Cookies', 18, 'dessert', '{"Dessert"}'::text[], 'Soft, chewy cookies made from just dates, oats, and hemp milk — no sugar, no butter, no fuss. Naturally sweetened and ready in 15 minutes.'),
  ('Chickpea Brownies', 30, 'dessert', '{"Dessert"}'::text[], 'Fudgy, flourless brownies made from blended chickpeas — packed with plant-based protein and naturally sweetened with raw honey. Ready in under 30 minutes.'),
  ('High Protein Dairy Free Cheesecake', 55, 'dessert', '{"Dessert"}'::text[], 'A creamy, protein-packed cheesecake made with chickpeas, cashews, and tofu — completely dairy-free and naturally sweetened with dates. Rich and satisfying with no compromise.'),
  ('4 Ingredient Flax and Pumpkin Seed Bread', 80, 'side', '{"Sides"}'::text[], 'A dense, hearty seed bread made with just four real ingredients — no flour, no yeast, no sugar. Naturally grain-free, high in fiber, and perfect toasted.'),
  ('Sweet Potato Brownie', 28, 'dessert', '{"Dessert"}'::text[], 'A flourless, fudgy brownie made from a single sweet potato. Dense and chocolatey with zero refined sugar — naturally sweetened with raw honey.'),
  ('No Bake Chocolate Cake', 20, 'dessert', '{"Dessert"}'::text[], 'A dense, smooth, and fudgy chocolate cake made with hard-boiled eggs and 100% dark chocolate — no oven needed. Rich, satisfying, and secretly packed with protein.'),
  ('Zucchini Roll-Up Enchiladas', 30, 'dinner', '{"Baked Goods"}'::text[], 'This veggie-packed version satisfies your craving for cheesy, saucy enchiladas without the processed tortillas or heavy fillers.'),
  ('Zucchini Lasagna with Fresh Ricotta', 40, 'dinner', '{"Baked Goods"}'::text[], 'This swap uses zucchini instead of pasta and fresh ricotta for a wholesome, comforting meal without the ultra-processed fillers.'),
  ('Zucchini Lasagna', 40, 'dinner', '{"Baked Goods"}'::text[], 'This swap replaces processed pasta with fresh zucchini for a nutrient-packed, wholesome alternative.'),
  ('Zucchini Chocolate Mousse', 20, 'dessert', '{"Dessert"}'::text[], 'A rich, creamy chocolate mousse made with just two ingredients — steamed zucchini and 100% dark chocolate. The hot zucchini melts the chocolate as it blends, creating a silky mousse that sets beautifully in the fridge. No one will guess the secret ingredient.'),
  ('Vegan Cashew Vanilla Icing', 10, 'dessert', '{"Dessert"}'::text[], 'Silky, dairy-free icing made from soaked raw cashews, raw honey, hemp milk, and vanilla. Creamy enough to frost a cake, clean enough to eat with a spoon. Credit: Jessica Laroche.'),
  ('Sweet Potato Salad', 45, 'lunch', '{"Salad"}'::text[], 'Roasted sweet potatoes over a bed of peppery arugula with creamy tahini dressing, feta, sliced avocado, and toasted pepitas. Simple, satisfying, and stunning on a platter.'),
  ('Sweet Potato Pizza Crust', 35, 'dinner', '{"Pizza"}'::text[], 'A 3-ingredient grain-free pizza crust made with mashed sweet potato and almond flour. No yeast, no rising, no fuss — just mix, flatten, and bake.'),
  ('Sweet Potato Hash & Eggs', 30, 'breakfast', '{"Breakfast"}'::text[], 'A one-skillet breakfast with tender sweet potato, poblano, kale, and eggs baked right into the hash. Ready in 30 minutes with real, whole-food ingredients.'),
  ('Sweet 4-Nut Granola', 42, 'breakfast', '{"Breakfast"}'::text[], 'A seriously loaded granola with four types of nuts, pumpkin seeds, almond butter, and raw honey. Crispier when spread thin across two baking sheets.'),
  ('Stovetop Popped Popcorn', 10, 'snack', '{"Snacks"}'::text[], 'This swap uses whole popcorn kernels and olive oil for a clean, crunchy snack without artificial additives.'),
  ('Spicy 4-Nut Granola', 42, 'snack', '{"Granola"}'::text[], 'All the crunch of the sweet version with a cayenne kick. Adjust the heat to your liking — bold and addictive.'),
  ('Sparkling Lemon Water', 3, 'drink', '{"Beverages"}'::text[], 'This swap satisfies the desire for something bubbly and flavorful without the artificial sweeteners found in diet soda.'),
  ('Simple Real Banana Bread', 55, 'breakfast', '{"Baked Goods"}'::text[], 'This simple banana bread uses whole, recognizable ingredients to deliver the same moist, sweet satisfaction without refined sugars or processed oils.'),
  ('Roasted Tomato Soup (also doubles as Marinara Sauce)', 50, 'dinner', '{"Soup"}'::text[], 'A dead-simple roasted tomato soup that also works beautifully as a marinara sauce. Just toss everything on a baking sheet, roast, and blend.'),
  ('Roasted Red Pepper & Spinach Frittata', 30, 'breakfast', '{"Breakfast"}'::text[], 'A vibrant, oven-finished frittata with roasted red peppers, wilted spinach, and crumbled feta. One skillet, 30 minutes, real ingredients.'),
  ('Real Food Tiramisu', 10, 'dessert', '{"Dessert"}'::text[], 'A no-bake, plant-based twist on tiramisu made with overnight oats, hemp milk, and mashed banana. Rich, creamy, and genuinely good for you.'),
  ('Real Food Pie Crust', 10, 'dessert', '{"Dessert"}'::text[], 'A two-ingredient no-bake pie crust made from dates and pecans. Press it into any pie pan and fill with your favorite real food filling — cheesecake, pecan pie, or anything else. No flour, no butter, no refined sugar.'),
  ('Real Food Pecan Pie', 60, 'dessert', '{"Dessert"}'::text[], 'A date-and-pecan crust filled with whole pecans, eggs, honey, and coconut oil. No corn syrup, no refined sugar — just pure, rich, real-food pecan pie. Add dark chocolate for an irresistible twist.'),
  ('Real Food Egg McMuffin', 10, 'breakfast', '{"Breakfast"}'::text[], 'A grain-free, whole-food take on the classic breakfast sandwich. Built on a 90 Second Bread English muffin and stacked with eggs, meat, and your favorite toppings.'),
  ('Real Food Cheesecake', 30, 'dessert', '{"Dessert"}'::text[], 'A shockingly simple two-ingredient cheesecake filling — just Greek yogurt and egg. Use our Real Food Pie Crust as the base, add honey for sweetness, and top with fresh fruit. Clean, creamy, and actually good for you.'),
  ('Real Food "Nutella" (Hazelnut)', 20, 'snack', '{"Sweet Treats"}'::text[], 'This DIY version satisfies your sweet tooth with the same creamy, chocolate-hazelnut flavor using just whole, clean ingredients.'),
  ('Real Food "Nutella" (Hazelnut Free)', 5, 'dessert', '{"Dessert"}'::text[], 'A two-minute chocolate spread made with raw cacao powder, honey, and hemp seeds — no hazelnuts, no refined sugar, no palm oil. Spread it on anything and feel zero guilt.'),
  ('Raw Dairy Honey Ice Cream', 10, 'dessert', '{"Dessert"}'::text[], 'Three-ingredient ice cream that''s impossibly creamy.'),
  ('Raw Chocolate Mousse', 10, 'dessert', '{"Dessert"}'::text[], 'A three-ingredient mousse that tastes indulgent but is completely clean. Avocado and banana blend into a silky base, then raw cacao powder turns it into a rich chocolate dream. Chill it and it sets like a real mousse.'),
  ('Perfect Sunny Side Up Eggs', 10, 'breakfast', '{"Breakfast"}'::text[], 'The easiest oven-baked sunny side up eggs with perfectly set whites and gloriously runny yolks. A drizzle of olive oil, salt, and red pepper flakes — that''s all you need for a protein-packed real food breakfast.'),
  ('Overnight Chia Pudding Bowl', 10, 'breakfast', '{"Breakfast"}'::text[], 'A hearty overnight bowl packed with oats, hemp seeds, fresh fruit, and pumpkin seeds — all softened in coconut water while you sleep. Zero cooking required.'),
  ('No-Bake Greek Yogurt Cheesecake', 10, 'dessert', '{"Sweet Treats"}'::text[], 'This swap captures the creamy, indulgent texture of cheesecake using Greek yogurt and a nut-based crust, without the processed sugars or additives.'),
  ('Medjool Date Cookies', 22, 'dessert', '{"Dessert"}'::text[], 'Soft, chewy cookies sweetened entirely by medjool dates — no refined sugar, just oats, oat flour, and the natural caramel richness of dates. Add chocolate chips to make them even better.'),
  ('Mediterranean Lentil Soup', 40, 'dinner', '{"Soup"}'::text[], 'A hearty, plant-powered soup with lentils, potatoes, and spinach in a rich tomato broth. Ready in 40 minutes and full of flavor.'),
  ('Lemon Zucchini Bread', 50, 'snack', '{"Bread"}'::text[], 'A bright, moist zucchini bread sweetened with raw honey and brightened with fresh lemon. Made with oat, coconut, or almond flour — no refined sugar, no seed oils.'),
  ('Lemon Bars', 30, 'dessert', '{"Dessert"}'::text[], 'Bright, zesty lemon bars with a simple almond flour crust and a honey-sweetened lemon filling. Top with fresh berries and optional shaved coconut.'),
  ('Kalamata Olive Hummus', 5, 'snack', '{"Dip"}'::text[], 'Creamy, blender hummus with chickpeas, tahini, lemon, and Kalamata olives. No preservatives, no mystery ingredients — just real food.'),
  ('Homemade Pistachio Milk', 2, 'drink', '{"Beverages"}'::text[], 'Naturally green-tinted and slightly sweet, pistachio milk is rich and creamy with a distinct nutty flavor. A beautiful, nutrient-dense alternative.'),
  ('Homemade Oat Milk', 2, 'drink', '{"Beverages"}'::text[], 'Creamy, slightly sweet, and perfect for coffee or cereal. Made with just oats and water — the most economical plant milk you can make at home.'),
  ('Homemade Nutty Date Bars', 10, 'dessert', '{"Sweet Treats"}'::text[], 'This swap combines dates, nuts, and 100% cacao for a naturally sweet, chewy, and satisfying alternative to Snickers.'),
  ('Homemade Italian Sausage Spiced Ground Meat', 15, 'dinner', '{"Fast Food"}'::text[], 'This swap captures the bold, herby flavors of Italian sausage without the preservatives and additives often found in store-bought versions.'),
  ('Homemade Italian Sausage Patties', 15, 'dinner', '{"Fast Food"}'::text[], 'This swap delivers the same bold Italian flavors using simple, whole ingredients without additives or preservatives.'),
  ('Homemade Honey Vanilla Marshmallow Alternative', 9, 'dessert', '{"Sweet Treats"}'::text[], 'This swap delivers the same fluffy, chewy texture using just four whole ingredients without corn syrup or additives.'),
  ('Homemade Hemp Milk', 2, 'drink', '{"Beverages"}'::text[], 'The easiest plant milk you can make — no soaking, no straining. Just hemp seeds, water, and an optional medjool date or two for natural sweetness. Ready in under a minute.'),
  ('Homemade Fruit Gummies', 7, 'snack', '{"Sweet Treats"}'::text[], 'These homemade fruit gummies use real fruit and gelatin for a chewy, naturally sweet treat without the artificial colors and sugar overload.'),
  ('Homemade Date Caramel Chocolate Bars', 20, 'dessert', '{"Sweet Treats"}'::text[], 'This swap gives you the same caramel-chocolate-cookie crunch without the ultra-processed ingredients.'),
  ('Homemade Crispy Puffed Rice Bars', 5, 'dessert', '{"Sweet Treats"}'::text[], 'This swap replicates the crispy texture and sweet flavor using whole ingredients and skips the marshmallows and processed additives.'),
  ('Homemade Chocolate Nut Bars', 10, 'dessert', '{"Sweet Treats"}'::text[], 'This swap combines the rich chocolate, caramel-like sweetness, and crunchy nuts you love in a Snickers without the ultra-processed ingredients.'),
  ('Homemade Beef Jerky', 250, 'snack', '{"Snacks"}'::text[], 'This simple homemade beef jerky uses just a few whole ingredients for a protein-packed snack without the added sugars, preservatives, or artificial flavorings found in store-bought versions.'),
  ('Homemade Almond Milk', 2, 'drink', '{"Beverages"}'::text[], 'Fresh almond milk with a clean, light flavor. Soak almonds overnight to bring out their natural creaminess — add a medjool date for a touch of sweetness.'),
  ('Ginger Dates', 15, 'dessert', '{"Dessert"}'::text[], 'Medjool dates stuffed with fresh ginger and coated in 100% dark chocolate. A warming, spicy-sweet bite with just three real ingredients — and optional sea salt for the finishing touch.'),
  ('Electrolyte Coconut Water', 5, 'drink', '{"Beverages"}'::text[], 'Natural sports drink replacement.'),
  ('Divine & Disappearing Cookies', 30, 'dessert', '{"Dessert"}'::text[], 'No refined sugar, no butter, no flour — just walnuts, Medjool dates, and a handful of pantry staples. Firm up in the fridge and disappear fast. Double the recipe.'),
  ('Dark Chocolate Date Bites', 15, 'dessert', '{"Dessert"}'::text[], 'A sweet treat with only three real ingredients. Medjool dates stuffed with almond butter, coated in dark chocolate, and finished with a pinch of sea salt.'),
  ('Crispy Roasted Chickpeas', 35, 'snack', '{"Snacks"}'::text[], 'Roasted chickpeas are a simple, whole-food alternative with a satisfying crunch and customizable seasoning.'),
  ('Crispy Potatoes', 35, 'side', '{"Sides"}'::text[], 'Baby potatoes baked cut-side down on a garlic-herb Parmesan paste — they come out golden, crispy, and impossible to stop eating.'),
  ('Crispy Baked Potato Slices', 30, 'side', '{"Salty & Crunchy"}'::text[], 'These baked potato slices deliver the same salty crunch with just three whole ingredients.'),
  ('Coconut Whipped Cream', 5, 'dessert', '{"Dessert"}'::text[], 'Three ingredients, five minutes. Full-fat coconut milk chilled until firm, then whipped with raw honey and vanilla into a cloud-like dairy-free topping.'),
  ('Citrus Honey Sparkler', 3, 'drink', '{"Beverages"}'::text[], 'This swap delivers the same fizzy, refreshing experience but uses natural flavors and a touch of unprocessed sweetness.'),
  ('Chickpea Salad Bowl', 25, 'lunch', '{"Salad"}'::text[], 'A hearty, Mediterranean-inspired bowl built on a pulse of chickpeas, tahini, and capers — layered over greens with blanched green beans, Kalamata olives, avocado, and fresh basil.'),
  ('Blender Banana Bread', 45, 'dessert', '{"Dessert"}'::text[], 'No flour, no refined sugar, no mixer needed. Just 5 real ingredients blended in a NutriBullet and baked in a pie dish. Done in 45 minutes.'),
  ('Birthday Cake Cookies', 25, 'dessert', '{"Dessert"}'::text[], 'Light, fluffy cookies made with just egg whites, applesauce, and coconut flour — studded with raspberries and ready in 15 minutes. All the fun of birthday cake without any of the junk. Makes 5 cookies.'),
  ('Best Buddha Bowl', 35, 'lunch', '{"Bowl"}'::text[], 'A fully loaded bowl with roasted sweet potato, massaged kale, fermented veggies, brown rice or quinoa, and a golden Turmeric Tahini Sauce. Colorful, nourishing, and completely real food.'),
  ('Bean & Artichoke Pasta Bowl', 17, 'lunch', '{"Pasta"}'::text[], 'A pantry-staple pasta bowl that comes together in 15 minutes. Grain-free pasta options, black beans, artichoke hearts, and olive oil — season to taste and adjust ratios as you like.'),
  ('Banana & Chickpea Pancakes', 15, 'breakfast', '{"Breakfast"}'::text[], 'Fluffy, naturally sweetened pancakes made with bananas, chickpeas, and eggs — no flour, no refined sugar. Ready in under 15 minutes.'),
  ('Avocado Chocolate Pudding', 5, 'dessert', '{"Sweet Treats"}'::text[], 'This swap delivers the same creamy, chocolatey satisfaction while using whole, nutrient-dense ingredients.'),
  ('90 Second Bread (English Muffin)', 4, 'snack', '{"Bread"}'::text[], 'A quick, grain-free bread made with just flaxseed and an egg — ready in 90 seconds flat. Perfect for a low-carb snack or sandwich swap.')
